Add-Type -AssemblyName System.Drawing; $src="eTech_Fusion-vector.png"; $bmp=[System.Drawing.Image]::FromFile($src); $size=64; $out=[System.Drawing.Bitmap]::new($size,$size); $g=[System.Drawing.Graphics]::FromImage($out); $g.Clear([System.Drawing.Color]::Transparent); $g.InterpolationMode=[System.Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic; $g.DrawImage($bmp,0,0,$size,$size); $out.Save("favicon.png",[System.Drawing.Imaging.ImageFormat]::Png); $g.Dispose(); $bmp.Dispose(); $out.Dispose(); Write-Output "created favicon.png"
